<template>
  <v-app>
    <v-app-bar color="white" dark>
      <v-toolbar-title>Dynamic Tables</v-toolbar-title>
    </v-app-bar>

    <v-main>
      <v-container fluid>
        <!-- Loop through each table in the parsed data -->
        <v-row
          v-for="(table, tableIndex) in tables"
          :key="tableIndex"
          class="table-section"
        >
          <v-col cols="12">
            <v-card outlined>
              <v-card-title>{{ formatTableName(table.name) }}</v-card-title>

              <!-- Table with headers and rows -->
              <v-simple-table>
                <!-- Table headers -->
                <thead>
                  <tr>
                    <th v-for="(header, colIndex) in table.headers" :key="colIndex">
                      {{ header }}
                    </th>
                  </tr>
                </thead>

                <!-- Table rows -->
                <tbody>
                  <tr v-for="(row, rowIndex) in table.rows" :key="rowIndex">
                    <td v-for="(cell, colIndex) in row" :key="colIndex">
                      <!-- Render input field if cell has ID, else display value -->
                      <v-text-field
                        v-if="cell.isPlaceholder"
                        v-model="cell.value"
                        :label="cell.id"
                        variant="outlined"
                        dense
                        @input="logCellUpdate(cell)"
                        class="table-cell-input"
                        hide-details
                      />
                      <span v-else>{{ cell.value }}</span>
                    </td>
                  </tr>
                </tbody>
              </v-simple-table>
            </v-card>
          </v-col>
        </v-row>

        <!-- Submit Button -->
        <v-btn @click="navigateToCheckboxPage" color="primary" class="mt-4">
          Next
          </v-btn>
      </v-container>
    </v-main>
  </v-app>
</template>

<script>
import { ref, onMounted } from 'vue';
import { useStore } from 'vuex';
import { useRouter, onBeforeRouteLeave } from 'vue-router';
import { fetchAndParseTables } from '@/utils/utility.js';
import axios from 'axios';

export default {
  setup() {
    const store = useStore();
    const router = useRouter();
    const tables = ref([]);
    const logCellUpdate = () => {
      };

    const loadPersistedTableValues = () => {
      console.log("Loading persisted structured table from Vuex...");
      tables.value = store.state.structuredTableData || [];
    };



      // Fetch and parse tables from the document template
      const loadDynamicTables = async () => {
        if (!store.state.selectedTemplate) {
          alert("No template selected. Please go back and select a template.");
          router.push({ name: "userOptionsPage" });
          return;
        }

        const hasPersistedData = store.state.structuredTableData.length > 0;

        if (!store.state.isNavigatingBack || !hasPersistedData) {
          console.log("Refreshing tables: Fetching template data...");
          const response = await axios.get(
            `/api/sow-template?filename=${encodeURIComponent(store.state.selectedTemplate)}`,
            { responseType: "arraybuffer" }
          );

          // Get parsed tables and empty table tags from the utility function
          const { parsedTables, emptyTableTags } = await fetchAndParseTables(response.data);

          // Set parsed tables to the component state
          tables.value = parsedTables;
          console.log("Template tables loaded:", tables.value);

          // Commit emptyTableTags to Vuex
          store.dispatch('saveEmptyTableTags', emptyTableTags);
          console.log("Empty table tags saved to Vuex:", emptyTableTags);
        } else {
          console.log("Navigating back: Loading persisted structured table data...");
          loadPersistedTableValues();
        }

        store.commit("setNavigatingBack", false);
      };



    // Build the final data object for docxtemplater
    const buildDocxtemplaterData = () => {
      console.log('Starting to build data object from table:', tables.value);
      const dataForDocxtemplater = {};

      // Loop through each table to gather data
      tables.value.forEach(table => {
        table.rows.forEach(row => {
          row.forEach(cell => {
            if (cell.isPlaceholder && cell.id) {
              // Map the placeholder ID to the user-entered value
              dataForDocxtemplater[cell.id] = cell.value;
            }
          });
        });
      });

      console.log('Data for Docxtemplater:', dataForDocxtemplater);
      return dataForDocxtemplater;
    };

    // Navigate to CheckboxPage.vue
    const navigateToCheckboxPage = () => {
      const docxtemplaterData = buildDocxtemplaterData();
      
      store.dispatch("saveTableData", docxtemplaterData); // Flattened data for Docxtemplater
      store.dispatch("saveStructuredTableData", tables.value); // Structured data for persistence
      
      console.log("Saved structured table data to Vuex:", tables.value);
      router.push({ name: "checkboxPage" });
    };


    const formatTableName = (name) => {
      return name.replace(/_/g, ' ').replace(/\b\w/g, (c) => c.toUpperCase());
    };

    onMounted(() => {
      loadDynamicTables();
    });

        // Insert onBeforeRouteLeave here
    onBeforeRouteLeave((to, from, next) => {
      store.commit('setNavigatingBack', true); // Set isNavigatingBack to true when navigating away
      next(); // Allow the navigation to proceed
    });

    return {
      tables,
      navigateToCheckboxPage,
      formatTableName,
      logCellUpdate
    };
  },
};
</script>


<style scoped>
.table-section {
  margin-bottom: 24px;
}

.v-card {
  margin: 16px;
  padding-bottom: 16px; /* Add padding to the bottom of the card */
}

/* Add padding, alignment, and border to table headers */
th {
  padding: 8px 12px;
  white-space: normal;
  text-align: center;
  font-weight: bold;
  border: 1px solid #ccc; /* Add border to the header cells */
  border-top-left-radius: 2px; /* Optional: round the top left corner */
  border-top-right-radius: 2px; /* Optional: round the top right corner */
  background-color: rgba(15, 101, 84, 0.644); /* Add a light background color for contrast */
}

/* Add padding, border, and row shading to table cells */
td {
  padding: 8px 12px;
  border: 1px solid #ccc;
  border-radius: 1px;
}

tr:nth-child(even) {
  background-color: #f9f9f9;
}

/* Adjust the text input width and add margin */
.v-text-field {
  min-width: 100px;
  max-width: 150px;
  width: 100%;
  margin: 4px;
  border-radius: 1px;
}

/* Optional: Round the corners of the entire table */
.v-simple-table {
  border-radius: 8px;
  overflow: hidden;
}
.table-cell-input .v-input__control {
  border: none !important; /* Remove the border */
  box-shadow: none !important; /* Remove any shadow */
  padding: 0 !important; /* Minimize padding */
}

.table-cell-input input {
  border: none !important; /* Remove input border */
  box-shadow: none !important; /* Remove input shadow */
  padding: 0 !important; /* Minimize input padding */
  font-size: 14px; /* Adjust font size */
  background-color: transparent !important; /* Make background transparent */
}

.table-cell-input .v-input__slot {
  border-radius: 0 !important; /* Remove any border-radius */
}

td {
  padding: 4px 8px; /* Adjust padding to make the input fit more naturally */
}
</style>


