import PizZip from 'pizzip';
import Docxtemplater from 'docxtemplater';


export const fetchTemplateAndParseData = async (docContent) => {
  const zip = new PizZip(docContent);
  const docxtemplater = new Docxtemplater(zip, {
    paragraphLoop: true,
    linebreaks: true,
  });

  const text = docxtemplater.getFullText();

  // Regex patterns for inputs, checkboxes, and dropdowns
  const inputRegex = /\{input:(.*?)\}/g;
  const sectionRegex = /\{[#/](.*?)\}/g;

  const inputsMap = {};
  const dropdowns = {}; // Store dropdown menus separately

  let match;

  // Parse input fields (text input)
  while ((match = inputRegex.exec(text)) !== null) {
    const fieldName = match[1].trim();

    if (!inputsMap[fieldName]) {
      inputsMap[fieldName] = {
        id: fieldName,
        label: fieldName,
        value: '', // Initial value can be empty
      };
    }
  }

  // Convert inputsMap to an array for dynamic inputs
  const inputs = Object.values(inputsMap);

  // Parse sections for checkboxes and dropdowns
  const stack = [];
  let root = { children: [] };
  let currentParent = root;

  while ((match = sectionRegex.exec(text)) !== null) {
    const tag = match[0];
    const content = match[1].trim();

    // Check if it's a dropdown menu by looking for the 'Select_' keyword
    if (tag.startsWith('{#Select_')) {
      const sectionId = content.trim();

      // Split the content by space to separate the descriptive part from the option (e.g., "Agile", "Waterfall")
      const parts = sectionId.split(' ');
      const dropdownId = parts[0]; // "Select_Testing_Type" or similar
      const optionValue = parts[1]; // e.g., "Agile" or "Waterfall"

      if (!dropdowns[dropdownId]) {
        dropdowns[dropdownId] = {
          id: dropdownId,
          options: [],
          selectedOption: null,
        };
      }

      // Add the option to the dropdown menu
      dropdowns[dropdownId].options.push({
        sectionName: sectionId,
        label: optionValue, // Use the second part of the content (e.g., "Agile", "Waterfall")
      });

      // Push to stack to ensure matching closing tag
      stack.push({
        id: sectionId,
        startTag: tag,
        startIndex: match.index,
      });
      currentParent.children.push({
        id: sectionId,
        label: sectionId,
        checked: true,
        children: [],
      });
    } else if (tag.startsWith('{/Select_')) {
      // Handle closing tags for dropdown menus
      const sectionId = content.trim();
      const lastSection = stack.pop(); // Try to pop the corresponding opening tag


      if (!lastSection || lastSection.id !== sectionId) {
        console.error('Mismatched closing tag:', tag);
      }
    } else if (tag.startsWith('{#')) {
      // Handle regular sections (checkboxes)
      const sectionId = content.trim();

      stack.push({
        id: sectionId,
        startTag: tag,
        startIndex: match.index,
      });
      currentParent.children.push({
        id: sectionId,
        label: sectionId,
        checked: true,
        children: [],
      });
    } else if (tag.startsWith('{/')) {
      // Handle regular section closing tags
      const sectionId = content.trim();

      const lastSection = stack.pop();

      if (!lastSection || lastSection.id !== sectionId) {
        console.error('Mismatched closing tag:', tag);
      }
    }
  }

  console.log("Final parsed sections:", root.children); // Log all parsed sections (checkboxes)
  console.log("Final dropdown menus:", dropdowns); // Log all parsed dropdown menus

  // Convert dropdowns to an array and ensure checkboxes don't include dropdown menus
  const dropdownsArray = Object.values(dropdowns);

  // Return inputs, checkboxes (non-dropdowns), and dropdowns separately
  return {
    inputs, // Dynamic input fields
    sections: root.children, // Only checkbox sections (not dropdowns)
    dropdowns: dropdownsArray, // Dropdown menus
  };
};



export const fetchDateFields = async (docContent) => {
  const zip = new PizZip(docContent);
  const docxtemplater = new Docxtemplater(zip, {
    paragraphLoop: true,
    linebreaks: true,
  });

  const text = docxtemplater.getFullText();

  const dateRegex = /\{date:(.*?)\}/g;
  const dateFields = new Map(); // Use a Map to ensure uniqueness

  let match;
  while ((match = dateRegex.exec(text)) !== null) {
    const fieldName = match[1].trim();
    
    // Only add the date field if it hasn't been added before
    if (!dateFields.has(fieldName)) {
      dateFields.set(fieldName, {
        id: fieldName,
        label: fieldName,  // Label for date picker
        value: '',         // Initial value is empty
        showDatePicker: false,  // Ensure showDatePicker is initialized
      });
    }
  }

  const uniqueDateFields = Array.from(dateFields.values());
  console.log("Parsed unique date fields:", uniqueDateFields);
  return uniqueDateFields;
};


export const fetchAndParseTables = async (docContent) => {
  try {
    const zip = new PizZip(docContent);
    const doc = new Docxtemplater(zip, {
      paragraphLoop: true,
      linebreaks: true,
    });
    
    const text = doc.getFullText();
    console.log('This is the full document:' ,text)

    const parsedTables = [];
    const emptyTableTags = {};
    const tableTagRegex = /{(table_start:[^}]+|table_end:[^}]+)}/g;
    const tableRegex = /{table_start:([^}]+)}([\s\S]*?){table_end:\1}/g;
    

    let match;
    while ((match = tableTagRegex.exec(text)) !== null) {
        const tag = match[1]; // Captured tag (e.g., 'table_start:Table1')
        emptyTableTags[tag] = ''; // Assign an empty value for each found tag
      }

      console.log("Extracted table tags with empty values:", emptyTableTags);

    while ((match = tableRegex.exec(text)) !== null) {
      const tableName = match[1];
      const tableContent = match[2].trim();

      // Extract headers
      const headerRegex = /\|\|\s*([^|]+?)\s*\|\|/g;
      let headers = [];
      let headerMatch;
      while ((headerMatch = headerRegex.exec(tableContent)) !== null) {
        headers.push(headerMatch[1].trim());
      }

      // Remove headers from table content
      const remainingContent = tableContent.replace(headerRegex, '').trim();



      // Split the remaining content into individual cells
        const cells = remainingContent.match(/(\w+|\{[^}]+\})/g) || [];

        // Group cells into rows based on the number of headers
        const rows = [];
        for (let i = 0; i < cells.length; i += headers.length) {
          const rowCells = cells.slice(i, i + headers.length).map(cell => {
            const placeholderMatch = cell.match(/^\{([^}]+)\}$/);
            return {
              id: placeholderMatch ? placeholderMatch[1] : '',
              value: placeholderMatch ? '' : cell,
              isPlaceholder: !!placeholderMatch,
            };
          });
          rows.push(rowCells);
        }



      // Construct the parsed table
      const parsedTable = {
        name: tableName,
        headers,
        rows,
      };

      parsedTables.push(parsedTable);
    
    }
    
    console.log("Final parsed tables:", parsedTables);
    return {
      parsedTables,
      emptyTableTags
    };
      
  } catch (error) {
    console.error('Error parsing tables from document:', error);
    return {
      parsedTables: [],
      emptyTableTags: {},
    };
  }
};
